/* SaleMgmtMapper.insertSaleInfo */
INSERT INTO CLS_SALE_INFO
(
	SALE_DT
	, ORGN_ID
	, SALE_ITM_CD
	, SALE_SRL_NUM
	, SALE_CNT
	, SALE_AMT
	, VAT
	, DPST_PROC_AMT
	, SALE_STAT_CD
	, ADJ_STAT_CD
	, CLS_ACNT_STDR_CD
	, PREPAY_YN
	, SALE_OCCR_SCTN_CD
	, SALE_OCCR_DT
	, SALE_RECVNPAY_ISSU_YN
	, SALE_RECVNPAY_ISSU_DT
	, CLS_ACNT_PROC_YN
	, CLS_ACNT_PROC_DT
	, CLS_ACNT_YM
	, INVC_ID
	, MV_REQ_NUM
	, CRDT_LOAN_APPL_DT
	, SRL_MGMT_NUM
	, SLP_DT
	, FILE_NM
	, REGST_ID
	, REG_DTTM
	, RVISN_ID
	, RVISN_DTTM
	, RMK
	, INOUT_ID
) VALUES (
	#{saleDt, jdbcType=VARCHAR}
	, #{orgnId, jdbcType=VARCHAR}
	, #{saleItmCd, jdbcType=VARCHAR}
	, #{saleSrlNum, jdbcType=NUMERIC}
	, #{saleCnt, jdbcType=INTEGER}
	, #{saleAmt, jdbcType=NUMERIC}
	, #{vat, jdbcType=NUMERIC}
	, #{dpstProcAmt, jdbcType=NUMERIC}
	, #{saleStatCd, jdbcType=VARCHAR}
	, #{adjStatCd, jdbcType=VARCHAR}
	, #{clsAcntStdrCd, jdbcType=VARCHAR}
	, NVL(#{prepayYn, jdbcType=VARCHAR}, 'N')
	, #{saleOccrSctnCd, jdbcType=VARCHAR}
	, #{saleOccrDt, jdbcType=VARCHAR}
	, #{saleRecvnpayIssuYn, jdbcType=VARCHAR}
	, #{saleRecvnpayIssuDt, jdbcType=VARCHAR}
	, NVL(#{clsAcntProcYn, jdbcType=VARCHAR}, 'N')
	, #{clsAcntProcDt, jdbcType=VARCHAR}
	, #{clsAcntYm, jdbcType=VARCHAR}
	, #{invcId, jdbcType=VARCHAR}
	, #{mvReqNum, jdbcType=VARCHAR}
	, #{crdtLoanApplDt, jdbcType=VARCHAR}
	, #{srlMgmtNum, jdbcType=VARCHAR}
	, #{slpDt, jdbcType=VARCHAR}
	, #{fileNm, jdbcType=VARCHAR}
	, #{userId, jdbcType=VARCHAR}
	, SYSDATE
	, #{userId, jdbcType=VARCHAR}
	, SYSDATE
	, #{rmk, jdbcType=VARCHAR}
	, #{inoutId, jdbcType=VARCHAR}
)

