/* SaleMgmtMapper.saveSaleRecvnpayInfo */
MERGE INTO CLS_SALE_RECVNPAY_INFO
USING DUAL
	ON (SALE_YM = #{saleYm, jdbcType=VARCHAR}
		AND ORGN_ID = #{orgnId, jdbcType=VARCHAR}
		AND SALE_ITM_CD = #{saleItmCd, jdbcType=VARCHAR})
WHEN MATCHED THEN
	UPDATE SET
		SALE_ACML_AMT = SALE_ACML_AMT + #{saleAmt, jdbcType=NUMERIC}
		, DPST_PROC_AMT = DPST_PROC_AMT + #{dpstProcAmt, jdbcType=NUMERIC}
		, RVISN_ID = #{userId, jdbcType=VARCHAR}
		, RVISN_DTTM = SYSDATE
WHEN NOT MATCHED THEN
	INSERT (
		SALE_YM
		, ORGN_ID
		, SALE_ITM_CD
		, PREV_MON_BAL
		, SALE_ACML_AMT
		, CLS_ACNT_PROC_AMT
		, DPST_PROC_AMT
		, REGST_ID
		, REG_DTTM
		, RVISN_ID
		, RVISN_DTTM
	) VALUES (
		#{saleYm, jdbcType=VARCHAR}
		, #{orgnId, jdbcType=VARCHAR}
		, #{saleItmCd, jdbcType=VARCHAR}
		, 0
		, #{saleAcmlAmt, jdbcType=VARCHAR}
		, 0
		, #{dpstProcAmt, jdbcType=NUMERIC}
		, #{userId, jdbcType=VARCHAR}
		, SYSDATE
		, #{userId, jdbcType=VARCHAR}
		, SYSDATE
	)
